mapper.select:
SELECT
id,
parameter_id    AS parameterId,
dimension_index AS dimensionIndex,
count,
resolution,
unit,
created_at      AS createdAt,
updated_at      AS updatedAt
FROM space_axis_y


        AND id = #{id}


        AND parameter_id = #{parameterId}


        AND dimension_index = #{dimensionIndex}


        AND count = #{count}


        AND resolution = #{resolution}


        AND unit = #{unit}


ORDER BY created_at DESC
